 56→export function ActionPanel({
 57→  actions,
 58→  dropdownOpen,
 59→  dropdownActions,
 60→  onDropdownClose,
 61→  contextLabel,
 62→}: ActionPanelProps) {
 63→  const actionsTriggerRef = useRef<HTMLButtonElement>(null);
 64→  const primary = actions[0];
 65→  if (!primary) return null;
 66→
 67→  const actionsButton = actions.find(a => a.label === 'Actions');
 68→
 69→  return (
 70→    <footer className="action-panel" role="toolbar" aria-label="Actions">
 71→      <div className="action-panel__left">
 72→        <RaycastLogo />
 73→        {contextLabel && (
 74→          <span className="action-panel__context">{contextLabel}</span>
 75→        )}
 76→      </div>
 77→      <div className="action-panel__right">
 78→        <button
 79→          className="action-panel__primary-action"
 80→          onClick={primary.onClick}
 81→          type="button"
 82→        >
 83→          <span className="action-panel__primary-label">{primary.label}</span>
 84→          <span className="action-panel__shortcut">{primary.shortcut}</span>
 85→        </button>
 86→        {actionsButton && (
 87→          <>
 88→            <span className="action-panel__separator" />
 89→            <button
 90→              ref={actionsTriggerRef}
 91→              className="action-panel__actions-trigger"
 92→              onClick={actionsButton.onClick}
 93→              type="button"
 94→              aria-haspopup="menu"
 95→              aria-expanded={dropdownOpen}
 96→            >
 97→              <span className="action-panel__actions-label">Actions</span>
 98→              <span className="action-panel__shortcut">
 99→                {actionsButton.shortcut}
100→              </span>
101→            </button>
102→          </>
103→        )}
104→      </div>
105→      <ActionsDropdown
106→        actions={dropdownActions}
107→        open={dropdownOpen}
108→        onClose={onDropdownClose}
109→        triggerRef={actionsTriggerRef}
110→      />
111→    </footer>
112→  );
113→}
