342→  }, [
343→    viewMode,
344→    handleSubmitSnippet,
345→    handleOpenCreateSnippet,
346→  ]);
347→
348→  const detail = selectedItem?.detail;
349→
350→  const dropdownActions = useMemo(
351→    () => [
352→      {
353→        label: 'Open',
354→        shortcut: <Kbd keys={['↵']} />,
355→        onClick: () => {
356→          if (selectedItem) {
357→            showToast({
358→              style: 'success',
359→              title: `Opened ${selectedItem.title}`,
360→            });
361→          }
362→        },
363→      },
364→      {
365→        label: 'Copy Name',
366→        shortcut: (
367→          <Kbd
368→            keys={[
369→              '⌘',
370→              'C',
371→            ]}
372→          />
