381→          }
382→        },
383→      },
384→      {
385→        label: 'Show Detail',
386→        shortcut: (
387→          <Kbd
388→            keys={[
389→              '⌘',
390→              'D',
391→            ]}
392→          />
393→        ),
394→        onClick: () => {
395→          showToast({
396→            style: 'info',
397→            title: 'Detail panel toggled',
398→          });
399→        },
400→      },
401→      {
402→        label: 'Create Snippet',
403→        shortcut: (
404→          <Kbd
405→            keys={[
406→              '⌘',
407→              'N',
408→            ]}
409→          />
410→        ),
411→        onClick: handleOpenCreateSnippet,
412→      },
413→      {
414→        label: 'Delete',
415→        shortcut: (
416→          <Kbd
