438→
439→  const activeDescendantId =
440→    viewMode === 'grid'
441→      ? filteredColors.length > 0
442→        ? `grid-item-${selectedIndex}`
443→        : undefined
444→      : allItems.length > 0
445→        ? `list-item-${selectedIndex}`
446→        : undefined;
447→
448→  return (
449→    <CommandPalette isLoading>
450→      <SearchBar
451→        value={query}
452→        onChange={handleQueryChange}
453→        activeDescendantId={activeDescendantId}
454→        breadcrumbs={breadcrumbs}
