462→              <FormTextField
463→                label="Name"
464→                value={snippetForm.name}
465→                onChange={v =>
466→                  setSnippetForm(prev => ({
467→                    ...prev,
468→                    name: v,
469→                  }))
470→                }
471→                placeholder="e.g. Email Signature"
472→                error={formErrors.name}
473→                autoFocus
474→              />
475→              <FormTextField
476→                label="Keyword"
477→                value={snippetForm.keyword}
478→                onChange={v =>
479→                  setSnippetForm(prev => ({
480→                    ...prev,
481→                    keyword: v,
482→                  }))
483→                }
484→                placeholder="e.g. !sig"
485→                description="Type this to expand the snippet"
486→              />
487→              <FormDropdown
488→                label="Category"
489→                value={snippetForm.category}
490→                onChange={v =>
491→                  setSnippetForm(prev => ({
492→                    ...prev,
493→                    category: v,
494→                  }))
495→                }
496→                options={SNIPPET_CATEGORIES}
497→                placeholder="Select a category"
498→              />
499→              <FormTextArea
500→                label="Snippet"
501→                value={snippetForm.snippet}
502→                onChange={v =>
503→                  setSnippetForm(prev => ({
504→                    ...prev,
505→                    snippet: v,
