  8→function renderActionPanel(
  9→  overrides: {
 10→    actions?: Action[];
 11→    dropdownOpen?: boolean;
 12→    dropdownActions?: DropdownAction[];
 13→    onDropdownClose?: () => void;
 14→    contextLabel?: string;
 15→  } = {},
 16→) {
 17→  const defaultActions: Action[] = [
 18→    {
 19→      label: 'Open',
 20→      shortcut: <span>Enter</span>,
 21→      onClick: vi.fn(),
 22→    },
 23→    {
 24→      label: 'Actions',
 25→      shortcut: <span>⌘K</span>,
 26→      onClick: vi.fn(),
 27→    },
 28→  ];
 29→
 30→  const defaultDropdownActions: DropdownAction[] = [
 31→    {
 32→      label: 'Delete',
 33→      shortcut: <span>⌘D</span>,
 34→      onClick: vi.fn(),
 35→    },
 36→    {
 37→      label: 'Move',
 38→      shortcut: <span>⌘M</span>,
 39→      onClick: vi.fn(),
 40→    },
 41→  ];
 42→
 43→  const props = {
 44→    actions: overrides.actions ?? defaultActions,
 45→    dropdownOpen: overrides.dropdownOpen ?? false,
 46→    dropdownActions: overrides.dropdownActions ?? defaultDropdownActions,
 47→    onDropdownClose: overrides.onDropdownClose ?? vi.fn(),
 48→    contextLabel: overrides.contextLabel,
 49→  };
 50→
 51→  return {
 52→    ...render(<ActionPanel {...props} />),
 53→    props,
 54→  };
 55→}
